select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where u.id = p.owneruserid and p.id = v.postid and p.id = c.postid and u.id = b.userid and p.id = ph.postid and p.answercount>=0 and p.commentcount>=0 and b."date"<=timestamp '2014-09-11 21:46:02' and u.reputation>=1 and u.reputation<=642 and u.downvotes>=0;
